  ('bookkeeper-moex-01776', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依照我國營利事業所得稅查核準則規定，下列營利事業繳納之稅捐，何者可依法以稅捐費用列支？', '["購買土地、房屋所繳納之契稅、印花稅", "進口貨物所繳納之關稅", "對本事業所擁有之不動產課徵之房屋稅、地價稅", "出售土地所繳納之土地增值稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
